solution.code:
def is_automorphic(n):
    if n < 0: return False
    sq = n * n
    while n > 0:
        if n % 10 != sq % 10:
            return False
        n //= 10
        sq //= 10
    return True

if __name__ == "__main__":
    print(f"5: {is_automorphic(5)}")
